package vendor

import (
	"io"
	"slices"

	"github.com/BurntSushi/toml"
)

const (
	SchemaVersion  = 2
	manifestHeader = "# Generated by govendor. DO NOT EDIT.\n\n"
)

// Manifest represents a govendor.toml file.
type Manifest struct {
	Schema           int                     `toml:"schema"`
	Hash             string                  `toml:"hash"`
	IncludePlatforms []string                `toml:"include_platforms,omitempty"`
	Workspace        *WorkspaceConfig        `toml:"workspace,omitempty"`
	Mod              map[string]ModuleConfig `toml:"mod"`
}

// WorkspaceConfig holds Go workspace metadata recorded in the manifest.
type WorkspaceConfig struct {
	Go            string   `toml:"go"`
	Toolchain     string   `toml:"toolchain,omitempty"`
	ModuleConfigs []string `toml:"modules"`
}

// ModuleConfig represents a single dependency entry in the manifest.
type ModuleConfig struct {
	Path         string   `toml:"-"`
	Version      string   `toml:"version"`
	Hash         string   `toml:"hash,omitempty"`
	GoVersion    string   `toml:"go,omitempty"`
	Packages     []string `toml:"packages,omitempty"`
	ReplacedPath string   `toml:"replaced,omitempty"`
	Local        string   `toml:"local,omitempty"`
}

// New builds a Manifest from resolved dependencies. Pass a non-nil workspace
// for workspace (go.work) projects.
func New(hash string, deps []ModuleConfig, includePlatforms []string, workspace *WorkspaceConfig) *Manifest {
	mod := make(map[string]ModuleConfig, len(deps))
	for _, m := range deps {
		mod[m.Path] = m
	}

	var recorded []string
	if len(includePlatforms) > 0 {
		recorded = make([]string, len(includePlatforms))
		copy(recorded, includePlatforms)
		slices.Sort(recorded)
	}

	return &Manifest{
		Schema:           SchemaVersion,
		Hash:             hash,
		IncludePlatforms: recorded,
		Workspace:        workspace,
		Mod:              mod,
	}
}

// Parse unmarshals a govendor.toml file into a Manifest. The Path field of
// each ModuleConfig is backfilled from its map key, since it is excluded from
// TOML encoding.
func Parse(data []byte) (*Manifest, error) {
	var m Manifest
	if err := toml.Unmarshal(data, &m); err != nil {
		return nil, err
	}
	for path, cfg := range m.Mod {
		cfg.Path = path
		m.Mod[path] = cfg
	}
	return &m, nil
}

// WriteTo encodes the manifest as TOML into w.
func (m *Manifest) WriteTo(w io.Writer) (int64, error) {
	cw := &countingWriter{w: w}

	if _, err := io.WriteString(cw, manifestHeader); err != nil {
		return cw.n, err
	}

	if err := toml.NewEncoder(cw).Encode(m); err != nil {
		return cw.n, err
	}

	return cw.n, nil
}

type countingWriter struct {
	w io.Writer
	n int64
}

func (c *countingWriter) Write(p []byte) (int, error) {
	n, err := c.w.Write(p)
	c.n += int64(n)
	return n, err
}
